#include <Arduino.h>
#include <avr/io.h>
#include <avr/interrupt.h>

void timer3Init() {
  // Timer 3 initialization for an Arduino-like microcontroller

  // Disable global interrupts
  cli();

  // Set Timer 3 to CTC mode (Clear Timer on Compare match)
  TCCR3A &= ~(1 << WGM30);
  TCCR3A &= ~(1 << WGM31);
  TCCR3B |= (1 << WGM32);
  TCCR3B &= ~(1 << WGM33);

  // Set compare match value for desired frequency
  OCR3A = 15624; // Example for 1 Hz frequency

  // Enable Timer 3 compare match A interrupt
  TIMSK3 |= (1 << OCIE3A);

  // Set Timer 3 prescaler to 256 and start the timer
  TCCR3B |= (1 << CS32);
  TCCR3B &= ~(1 << CS31);
  TCCR3B &= ~(1 << CS30);

  // Enable global interrupts
  sei();
}

// Interrupt service routine for Timer 3 compare match A
ISR(TIMER3_COMPA_vect) {
  // Your timer interrupt code here
  // For example: Toggle digital pin 13 on Arduino
  digitalWrite(13, !digitalRead(13));
}

void setup() {
  // Set digital pin 13 as output for Arduino
