#include <stdio.h>
#include <stdlib.h>
#include <vxWorks.h>
#include <wdLib.h>
#include <taskLib.h>

// Timer3 handler function
void timer3Handler(int count) {
    printf("Timer 3 event - count: %d\n", count++);

    // Re-start the timer with new ticks count
    int ticks = 5 * sysClkRateGet(); // Set interval to 5 seconds
    WDOG_ID timer3Wd = wdCreate();   // Create a watchdog timer object for Timer 3
    wdStart(timer3Wd, ticks, (FUNCPTR)timer3Handler, count);
}

void timer3Init() {
    int ticks = 5 * sysClkRateGet(); // Set the interval to 5 seconds
    int count = 0;                   // Set the initial count value
    WDOG_ID timer3Wd = wdCreate();   // Create a watchdog timer object for Timer 3
    wdStart(timer3Wd, ticks, (FUNCPTR)timer3Handler, count); // Start the timer, call timer3Handler on timeout with count as the argument
}

int main(void)
{
    // Initialize Timer 3
    timer3Init();

    // Main task loop
    while (1) {
        // Do nothing, Timer3 will handle the task
        taskDelay(100);
    }

    return 0;
}
```

